// Generated by Claude Opus 4.6

import { BackupItem } from '@eclipse-che/common';
import {
  Dropdown,
  DropdownItem,
  DropdownList,
  FormGroup,
  MenuToggle,
} from '@patternfly/react-core';
import React, { useState } from 'react';

export type Props = {
  backups: BackupItem[];
  selectedBackup: BackupItem | undefined;
  onChange: (backup: BackupItem | undefined) => void;
};

export const BackupSelectorField: React.FC<Props> = ({ backups, selectedBackup, onChange }) => {
  const [isOpen, setIsOpen] = useState(false);

  if (backups.length === 0) {
    return null;
  }

  const handleSelect = (backup: BackupItem) => {
    setIsOpen(false);
    onChange(backup);
  };

  const toggleLabel = selectedBackup
    ? `${selectedBackup.workspaceName}${selectedBackup.workspaceExists ? ' (Active)' : ' (Deleted)'}`
    : 'Select a backup to restore';

  return (
    <FormGroup fieldId="restore-backup-select" label="Select a backup">
      <Dropdown
        onOpenChange={isOpen => setIsOpen(isOpen)}
        toggle={toggleRef => (
          <MenuToggle
            ref={toggleRef}
            id="restore-backup-select-toggle"
            onClick={() => setIsOpen(prev => !prev)}
            isExpanded={isOpen}
            data-testid="backup-select"
          >
            {toggleLabel}
          </MenuToggle>
        )}
        isOpen={isOpen}
      >
        <DropdownList>
          {backups.map(backup => (
            <DropdownItem key={backup.imageUrl} onClick={() => handleSelect(backup)}>
              {backup.workspaceName}
              {backup.workspaceExists ? ' (Active)' : ' (Deleted)'}
            </DropdownItem>
          ))}
        </DropdownList>
      </Dropdown>
    </FormGroup>
  );
};
